mapper.select:
SELECT q.*, s.subject_name, t.real_name as teacher_name
FROM question q
LEFT JOIN subject s ON q.subject_id = s.subject_id
LEFT JOIN teacher t ON q.create_by = t.teacher_id


        AND (q.question_content LIKE CONCAT('%', #{keyword}, '%')
             OR (q.knowledge_point IS NOT NULL AND q.knowledge_point LIKE CONCAT('%', #{keyword}, '%')))


        AND q.subject_id = #{subjectId}


        AND q.question_type = #{questionType}


        AND q.difficulty = #{difficulty}


ORDER BY q.create_time DESC
